     1→/**
     2→ * MMS WebSocket Hub Types
     3→ *
     4→ * Type definitions for WebSocket message protocols, events, and payloads.
     5→ * Implements real-time communication for canvas updates, optimizer progress,
     6→ * and collaborative editing.
     7→ *
     8→ * @see specs/005-api.md Section 5.14 (WebSocket Events)
     9→ */
    10→
    11→// =============================================================================
    12→// Base Message Types
    13→// =============================================================================
    14→
    15→/** Direction of WebSocket messages */
    16→export type MessageDirection = 'client-to-server' | 'server-to-client' | 'bidirectional';
    17→
    18→/** Base WebSocket message structure */
    19→export interface WebSocketMessage<T = unknown> {
    20→  type: string;
    21→  data?: T;
    22→  timestamp?: string;
    23→  correlationId?: string;
    24→}
    25→
    26→// =============================================================================
    27→// Client → Server Messages
    28→// =============================================================================
    29→
    30→/** Authentication request sent after connection */
    31→export interface AuthMessage extends WebSocketMessage<{ token: string }> {
    32→  type: 'AUTH';
    33→  data: { token: string };
    34→}
    35→
    36→/** Subscribe to canvas region updates */
    37→export interface CanvasSubscribeMessage extends WebSocketMessage<CanvasSubscriptionRegion> {
    38→  type: 'canvas:subscribe';
    39→  data: CanvasSubscriptionRegion;
    40→}
    41→
    42→/** Unsubscribe from canvas region updates */
    43→export interface CanvasUnsubscribeMessage extends WebSocketMessage<{ subscriptionId: string }> {
    44→  type: 'canvas:unsubscribe';
    45→  data: { subscriptionId: string };
    46→}
    47→
    48→/** Request to move a PM via drag-and-drop */
    49→export interface MovePmRequest extends WebSocketMessage<MovePmRequestData> {
    50→  type: 'canvas:move_pm';
    51→  data: MovePmRequestData;
    52→}
    53→
    54→/** Ping message for keepalive */
    55→export interface PingMessage extends WebSocketMessage<void> {
    56→  type: 'ping';
    57→}
    58→
    59→// =============================================================================
    60→// Server → Client Messages
    61→// =============================================================================
    62→
    63→/** Authentication result */
    64→export interface AuthResultMessage extends WebSocketMessage<AuthResultData> {
    65→  type: 'AUTH_RESULT';
    66→  data: AuthResultData;
    67→}
    68→
    69→/** PM schedule updated event */
    70→export interface PmUpdatedEvent extends WebSocketMessage<PmUpdatedData> {
    71→  type: 'canvas:pm_updated';
    72→  data: PmUpdatedData;
    73→}
    74→
    75→/** PM lock/unlock event */
    76→export interface PmLockedEvent extends WebSocketMessage<PmLockedData> {
    77→  type: 'canvas:pm_locked';
    78→  data: PmLockedData;
    79→}
    80→
    81→/** Man-hour projections updated event */
    82→export interface ManhourUpdatedEvent extends WebSocketMessage<ManhourUpdatedData> {
    83→  type: 'canvas:manhour_updated';
    84→  data: ManhourUpdatedData;
    85→}
    86→
    87→/** Drift analysis updated event */
    88→export interface DriftUpdatedEvent extends WebSocketMessage<DriftUpdatedData> {
    89→  type: 'canvas:drift_updated';
    90→  data: DriftUpdatedData;
    91→}
    92→
    93→/** Optimizer job progress event */
    94→export interface OptimizerProgressEvent extends WebSocketMessage<OptimizerProgressData> {
    95→  type: 'optimizer:progress';
    96→  data: OptimizerProgressData;
    97→}
    98→
    99→/** Optimizer job complete event */
   100→export interface OptimizerCompleteEvent extends WebSocketMessage<OptimizerCompleteData> {
   101→  type: 'optimizer:complete';
   102→  data: OptimizerCompleteData;
   103→}
   104→
   105→/** PM move result */
   106→export interface MovePmResultMessage extends WebSocketMessage<MovePmResultData> {
   107→  type: 'canvas:move_pm_result';
   108→  data: MovePmResultData;
   109→}
   110→
   111→/** Subscription confirmed */
   112→export interface SubscriptionConfirmedMessage extends WebSocketMessage<SubscriptionConfirmedData> {
   113→  type: 'canvas:subscription_confirmed';
   114→  data: SubscriptionConfirmedData;
   115→}
   116→
   117→/** Pong response to ping */
   118→export interface PongMessage extends WebSocketMessage<void> {
   119→  type: 'pong';
   120→}
   121→
   122→/** Error message */
   123→export interface ErrorMessage extends WebSocketMessage<ErrorData> {
   124→  type: 'error';
   125→  data: ErrorData;
   126→}
   127→
   128→// =============================================================================
   129→// Data Payloads
   130→// =============================================================================
   131→
   132→/** Canvas subscription region */
   133→export interface CanvasSubscriptionRegion {
   134→  trainIds?: string[];
   135→  depotIds?: string[];
   136→  fromDate: string;
   137→  toDate: string;
   138→  zoomLevel: 'STRATEGIC' | 'TACTICAL' | 'OPERATIONAL';
   139→}
