/**
 * Handle canvas subscription request
 */
private handleSubscribe(connectionId: string, region: CanvasSubscriptionRegion): void {
  const connection = this.connections.get(connectionId);
  if (!connection || connection.state !== 'authenticated') {
    this.sendError(connectionId, 'UNAUTHORIZED', 'Must be authenticated to subscribe');
    return;
  }

  if (connection.subscriptions.size >= MAX_SUBSCRIPTIONS_PER_CLIENT) {
    this.sendError(connectionId, 'MAX_SUBSCRIPTIONS', `Maximum ${MAX_SUBSCRIPTIONS_PER_CLIENT} subscriptions allowed`);
    return;
  }

  const subscriptionId = randomUUID();
  connection.subscriptions.set(subscriptionId, region);

  // Create room for this subscription if it doesn't exist
  const roomId = this.getCanvasRoomId(region);
  if (!this.rooms.has(roomId)) {
    this.createRoom(roomId, 'canvas', { region });
  }
  this.joinRoom(connectionId, roomId);

  // Count trains in region (simplified - would query DB in production)
  const trainCount = region.trainIds?.length ?? 0;

  this.send(connectionId, {
    type: 'canvas:subscription_confirmed',
    data: {
      subscriptionId,
      region,
      trainCount,
    },
  });

  this.log.debug({ connectionId, subscriptionId, region }, 'Canvas subscription created');
}

/**
 * Handle canvas unsubscription request
 */
private handleUnsubscribe(connectionId: string, subscriptionId: string): void {
  const connection = this.connections.get(connectionId);
  if (!connection) return;

  const region = connection.subscriptions.get(subscriptionId);
  if (region) {
    connection.subscriptions.delete(subscriptionId);

    // Leave the room if this was the only subscription
    const roomId = this.getCanvasRoomId(region);
    this.leaveRoom(connectionId, roomId);
  }

