/**
 * MMS Error Classes
 *
 * Typed error classes for consistent error handling across the application.
 * Each error includes a code for client-side handling and logging.
 *
 * Error code format: CATEGORY_NNN
 * - FILE_001-099: File/CSV processing errors
 * - ROW_001-099: Row/record validation errors
 * - SYS_001-099: System/infrastructure errors
 * - BUS_001-099: Business logic errors
 * - AUTH_001-099: Authentication/authorization errors
 * - EXT_001-099: External system errors (Maximo, etc.)
 *
 * @see specs/004-backend-specification.md Section 4.15
 */

/**
 * Base error class for all MMS errors
 */
export abstract class MmsError extends Error {
  abstract readonly code: string;
  abstract readonly statusCode: number;
  readonly isOperational: boolean = true;
  readonly timestamp: Date = new Date();
  readonly context?: Record<string, unknown>;

  constructor(message: string, context?: Record<string, unknown>) {
    super(message);
    this.name = this.constructor.name;
    this.context = context;
    Error.captureStackTrace(this, this.constructor);
  }

  toJSON() {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      statusCode: this.statusCode,
      timestamp: this.timestamp.toISOString(),
      ...(this.context && { context: this.context }),
    };
  }
}

